/**
 * Scans deploy-assets/als/ for each ALS name referenced in deploy.config.json,
 * finds the .wasm file in each directory, and writes
 * deploy-assets/generated-als-info.mjs.
 *
 * The generated file is imported by src/lib/runtime/interface.ts at build time
 * (Vite inlines it into the compiled bundle). It is gitignored — regenerated by
 * `npm run setup` and by the predev/precheck/prebuild hooks.
 *
 * Usage: node deploy-assets/generate-als-info.mjs
 */

import { writeFileSync } from 'node:fs'
import { join, dirname, relative } from 'node:path'
import { fileURLToPath } from 'node:url'
import { getSelectedAlsVersions, REPO_ROOT } from './resolve-deploy-config.mjs'

const DEPLOY_ASSETS = dirname(fileURLToPath(import.meta.url))
const OUT_PATH = join(DEPLOY_ASSETS, 'generated-als-info.mjs')

function main() {
  let versions
  try {
    versions = getSelectedAlsVersions()
  } catch {
    versions = []
  }

  const info = {}
  for (const v of versions) {
    if (v.wasmFilename) info[v.version] = { wasmFilename: v.wasmFilename }
  }

  const lines = [
    '// Generated by deploy-assets/generate-als-info.mjs — do not edit by hand.',
    '// Re-run `npm run setup` after changing deploy.config.json or als/ directory contents.',
    '',
    '/** @type {Record<string, { wasmFilename: string }>} */',
    `export const GENERATED_ALS_INFO = ${JSON.stringify(info, null, 2)}`,
    '',
  ]
  writeFileSync(OUT_PATH, lines.join('\n'))
  const n = Object.keys(info).length
  console.log(`Wrote ${n} ALS version${n === 1 ? '' : 's'} to ${relative(REPO_ROOT, OUT_PATH)}`)
}

main()
